def best_root_leaf_sum(spec: dict) -> int:
    """Largest base-to-leaf path sum in the subtree rooted at base."""
    v = spec["vals"][spec["base"]]
    kids = spec["kids"].get(spec["base"], [])
    if not kids:
        return v
    best = None
    for c in kids:
        s = best_root_leaf_sum({"kids": spec["kids"], "vals": spec["vals"], "base": c})
        if best is None or s > best:
            best = s
    return v + best

