def deepest_leaf_name(spec: dict) -> str:
    """Name of the deepest leaf under base; ties break to the smaller name."""
    kids = spec["kids"]
    stack = [(spec["base"], 0)]
    best_d = -1
    best_n = ""
    while stack:
        cur, d = stack.pop()
        cs = kids.get(cur, [])
        if not cs:
            if d > best_d or (d == best_d and cur < best_n):
                best_d = d
                best_n = cur
        else:
            for c in cs:
                stack.append((c, d + 1))
    return best_n

