node Frond { has name: str; }

walker DeepProbe {
    has depth: int = 0;
    has leaf: str = "";
    can seek with Frond entry {
        children = [-->];
        if not children { self.depth = 0; self.leaf = here.name; }
        else {
            bd = -1; bn = "";
            for c in children {
                w = c spawn DeepProbe();
                cd = w.depth + 1;
                if cd > bd or (cd == bd and w.leaf < bn) { bd = cd; bn = w.leaf; }
            }
            self.depth = bd; self.leaf = bn;
        }
    }
}

