def level_signed_sum(spec: dict) -> int:
    """Alternating-level sum: the base level adds, the next subtracts, and so on."""
    total = 0
    stack = [(spec["base"], 1)]
    while stack:
        cur, sign = stack.pop()
        total += sign * spec["vals"][cur]
        for c in spec["kids"].get(cur, []):
            stack.append((c, -sign))
    return total

