def eval_op_tree(spec: dict) -> int:
    """Evaluate an expression tree of '+' and '*' nodes over integer leaves."""
    kids = spec["kids"].get(spec["base"], [])
    if not kids:
        return spec["vals"][spec["base"]]
    parts = []
    for c in kids:
        parts.append(eval_op_tree({"kids": spec["kids"], "ops": spec["ops"], "vals": spec["vals"], "base": c}))
    if spec["ops"][spec["base"]] == "+":
        return sum(parts)
    out = 1
    for p in parts:
        out *= p
    return out

