def heavy_subtree_count(spec: dict) -> int:
    """Count nodes whose subtree holds at least half of all nodes under base."""
    kids = spec["kids"]
    order = []
    stack = [spec["base"]]
    while stack:
        cur = stack.pop()
        order.append(cur)
        stack.extend(kids.get(cur, []))
    size = {}
    for cur in reversed(order):
        size[cur] = 1 + sum(size[c] for c in kids.get(cur, []))
    total = size[spec["base"]]
    return sum(1 for n in order if 2 * size[n] >= total)

